import { LedgerErrorReason } from "../../../../errors/src";
import { LedgerCustom } from './ledger-custom';
/**
 * Type for standard ledger error data
 */
export type LedgerErrorData<TCustom extends LedgerCustom = LedgerCustom> = {
    reason: LedgerErrorReason;
    detail: string;
    custom?: TCustom;
};
/**
 * Type for custom errors. This is returned when the error is defined by
 * a third party system, such as a proxy bridge in anchor forwarding
 */
export type CustomErrorData = Record<string, unknown>;
/**
 * Type for error `data` sent in error response records.
 * Error response has standard structure with:
 * - hash
 * - data:
 * - meta
 */
export type ErrorData<TCustom extends LedgerCustom = LedgerCustom> = LedgerErrorData<TCustom> | CustomErrorData;
